#!/usr/bin/env node
const { spawn, spawnSync, execSync } = require('child_process')
const fs = require('fs')

try {
  process.env = require('../../../env.json')
} catch {
  process.env = { PORT: '8080' }
}
const {
  BITCOIN_RPCUSER,
  BITCOIN_RPCPASSWORD,
  BITCOIN_RPCPORT,
  LIGHTNING_DIR_4,
  LIGHTNING_DIR_5,
  LIGHTNING_DIR_6
} = process.env

const LIGHTNING_DIRS = [LIGHTNING_DIR_4, LIGHTNING_DIR_5, LIGHTNING_DIR_6]
const LIGHTNING_PORTS = [9740, 9741, 9742]
const sleep = (ms) => new Promise(r => setTimeout(r, ms))
const log = console.log

module.exports = {
  async start () {
    log('=== Starting Lightning nodes (node4–node6) ===')
    LIGHTNING_DIRS.forEach((dir) => {
      if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true })
    })

    LIGHTNING_DIRS.forEach((dir, i) => {
      const args = [
        '--network=regtest',
        `--lightning-dir=${dir}`,
        `--bitcoin-rpcuser=${BITCOIN_RPCUSER}`,
        `--bitcoin-rpcpassword=${BITCOIN_RPCPASSWORD}`,
        '--bitcoin-rpcconnect=127.0.0.1',
        `--bitcoin-rpcport=${BITCOIN_RPCPORT}`,
        `--addr=127.0.0.1:${LIGHTNING_PORTS[i]}`,
        `--log-file=${dir}/debug.log`,
        '--daemon'
      ]
      log(`→ Starting lightningd for ${dir}`)
      const child = spawn('lightningd', args, { detached: true, stdio: 'ignore' })
      child.unref()
    })

    await sleep(3000)
    const check = spawnSync('pgrep', ['-x', 'lightningd'])
    if (check.status === 0) log('✅ Lightning nodes running.')
    else log('⚠️ Lightning nodes failed to start.')
  },

  async stop () {
    log('Stopping lightningd (best effort)...')
    try {
      const running = execSync('pgrep -x lightningd', { stdio: 'pipe', encoding: 'utf8' }).trim()
      if (running) {
        execSync('pkill -f lightningd', { stdio: 'ignore' })
        log('✅ lightningd stopped.')
      }
    } catch {
      log('No lightningd processes found.')
    }
  }
}
